import requests
import json
from requests.adapters import HTTPAdapter
from urllib3.util.retry import Retry

class KongAdminClient:
    def __init__(self, kong_admin_url, admin_token=None):
        self.kong_admin_url = kong_admin_url.rstrip('/')
        self.session = requests.Session()
        
        # Configure retry strategy
        retry_strategy = Retry(
            total=3,
            backoff_factor=1,
            status_forcelist=[429, 500, 502, 503, 504],
        )
        adapter = HTTPAdapter(max_retries=retry_strategy)
        self.session.mount("http://", adapter)
        self.session.mount("https://", adapter)
        
        # Add authentication header if token provided
        if admin_token:
            self.session.headers.update({'X-Kong-Admin-Token': admin_token})
    
    def create_service(self, service_name, url, protocol='http'):
        """Create a service in Kong"""
        service_data = {
            'name': service_name,
            'url': url,
            'protocol': protocol
        }
        
        response = self.session.post(
            f'{self.kong_admin_url}/services',
            json=service_data
        )
        
        if response.status_code == 201:
            print(f"Service {service_name} created successfully")
            return response.json()
        else:
            print(f"Failed to create service {service_name}: {response.text}")
            return None
    
    def create_route(self, service_id, routes_config):
        """Create a route for a service"""
        route_data = {
            'service': {'id': service_id},
            **routes_config
        }
        
        response = self.session.post(
            f'{self.kong_admin_url}/routes',
            json=route_data
        )
        
        if response.status_code == 201:
            print(f"Route created successfully for service {service_id}")
            return response.json()
        else:
            print(f"Failed to create route: {response.text}")
            return None
    
    def create_upstream(self, upstream_name, algorithm='round-robin'):
        """Create an upstream in Kong"""
        upstream_data = {
            'name': upstream_name,
            'algorithm': algorithm
        }
        
        response = self.session.post(
            f'{self.kong_admin_url}/upstreams',
            json=upstream_data
        )
        
        if response.status_code == 201:
            print(f"Upstream {upstream_name} created successfully")
            return response.json()
        else:
            print(f"Failed to create upstream {upstream_name}: {response.text}")
            return None
    
    def create_target(self, upstream_id, target_host, target_port=8000):
        """Create a target for an upstream"""
        target_data = {
            'upstream': {'id': upstream_id},
            'target': f'{target_host}:{target_port}'
        }
        
        response = self.session.post(
            f'{self.kong_admin_url}/upstreams/{upstream_id}/targets',
            json=target_data
        )
        
        if response.status_code == 201:
            print(f"Target {target_host}:{target_port} added to upstream {upstream_id}")
            return response.json()
        else:
            print(f"Failed to add target: {response.text}")
            return None
    
    def create_plugin(self, plugin_config):
        """Create a plugin in Kong"""
        response = self.session.post(
            f'{self.kong_admin_url}/plugins',
            json=plugin_config
        )
        
        if response.status_code == 201:
            print("Plugin created successfully")
            return response.json()
        else:
            print(f"Failed to create plugin: {response.text}")
            return None

